1	// Edge function: get-listing-detail (US-039)
2	//
3	// Contract:
4	//   POST { listing_id: string }
5	//     → 200 {
6	//         listing:          <row from public.listings>,
7	//         pre_conditions:   <rows from listing_conditions where kind='pre'>,
8	//         post_conditions:  <rows from listing_conditions where kind='post'>,
9	//         sample_videos:    <rows from sample_videos>,
10	//         eligibility: {
11	//           eligible:                boolean,
12	//           failed_conditions:       Array<{metric, platform, required, actual}>,
13	//           has_active_application:  boolean,
14	//         }
15	//       }
16	//     → 400 { error: 'INVALID_JSON' | 'INVALID_REQUEST' }
17	//     → 401 { error: 'UNAUTHORIZED' }
18	//     → 403 { error: 'FORBIDDEN' }       // non-creator role
19	//     → 404 { error: 'LISTING_NOT_FOUND' } // also covers draft listings for non-owners
20	//     → 500 { error: 'SERVER_MISCONFIGURED' | 'DB_ERROR' }
21	//
22	// Auth: Marketify JWT (HS256, MARKETIFY_JWT_SECRET). Verifies via
23	//       _shared/jwt.ts and asserts role='creator'. Deployed with
24	//       verify_jwt=false at the gateway because the gateway only knows
25	//       about Supabase's own JWT secret — the handler enforces auth.
26	//
27	// Response shape — primary reference is docs/tech-architecture.md §5.4
28	// (the spec's `failed_conditions: Array<{metric, required, actual}>` wins
29	// over the story's `reasons: string[]`; spec is authoritative per the
30	// Ralph iteration rules). `pre_conditions` / `post_conditions` are split
31	// at the edge per the story AC — the DB persists them in a single
32	// `listing_conditions` table discriminated by `kind`.
33	//
34	// Eligibility — only PRE conditions gate apply-time eligibility per
35	// docs/tech-architecture.md §6.3 ("Pre-conditions: evaluated on all
36	// posts; post-conditions: evaluated on submissions"). POST conditions
37	// are returned in the response for the UI to display but do not
38	// contribute to `eligible` / `failed_conditions`.
39	//
40	// Fail-closed on missing metrics (§3d): when the creator hasn't been
41	// scraped yet (or a specific platform field is NULL), the PRE condition
42	// keyed on that field fails — the spec calls this out explicitly for
43	// Instagram `min_avg_views_last_n` ("Listings that require … treat null
44	// as ineligible (fail-closed).") and we apply the same rule uniformly.
45	
46	import { createClient } from "npm:@supabase/supabase-js@2";
47	import { verifyJwt } from "../_shared/jwt.ts";
48	import { corsHeaders } from "../_shared/cors.ts";
49	
50	const UUID_RE =
51	  /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
52	
53	type Platform = "tiktok" | "instagram";
54	type ConditionKind = "pre" | "post";
55	
56	interface ConditionRow {
57	  id: string;
58	  listing_version_id: string;
59	  kind: ConditionKind;
60	  metric: string;
61	  platform: Platform | null;
62	  operator: string;
63	  numeric_threshold: string | number | null;
64	  text_threshold: string | null;
65	  bool_threshold: boolean | null;
66	  created_at: string;
67	}
68	
69	interface CreatorProfileRow {
70	  tiktok_follower_count: number | null;
71	  tiktok_avg_views_last_10: number | null;
72	  tiktok_total_likes: number | null;
73	  tiktok_video_count: number | null;
74	  tiktok_is_verified: boolean | null;
75	  instagram_follower_count: number | null;
76	  instagram_avg_views_last_10: number | null;
77	  instagram_media_count: number | null;
78	}
79	
80	interface FailedCondition {
81	  metric: string;
82	  platform: Platform | null;
83	  required: number | boolean;
84	  actual: number | boolean | null;
85	}
86	
87	interface DetailRequest {
88	  listing_id?: unknown;
89	}
90	
91	function jsonResponse(status: number, body: unknown): Response {
92	  return new Response(JSON.stringify(body), {
93	    status,
94	    headers: { ...corsHeaders, "Content-Type": "application/json" },
95	  });
96	}
97	
98	function bearerToken(req: Request): string | null {
99	  const raw = req.headers.get("Authorization") ??
100	    req.headers.get("authorization");
101	  if (!raw) return null;
102	  const m = raw.match(/^Bearer\s+(.+)$/i);
103	  return m ? m[1].trim() : null;
104	}
105	
106	// Evaluate a single pre-condition against the creator's denormalized
107	// metrics. Returns `null` on pass, or the failed-condition detail on fail.
108	// Missing data (null actual for a numeric threshold) fails closed per §3d.
109	function evaluatePreCondition(
110	  condition: ConditionRow,
111	  metrics: CreatorProfileRow,
112	): FailedCondition | null {
113	  const { metric, platform, operator } = condition;
114	  if (operator === "gte") {
115	    const required = Number(condition.numeric_threshold);
116	    if (!Number.isFinite(required)) return null; // malformed row — skip, not fail
117	    const actual = readNumericMetric(metrics, platform, metric);
118	    if (actual === null || actual < required) {
119	      return { metric, platform, required, actual };
120	    }
121	    return null;
122	  }
123	  if (operator === "bool") {
124	    const required = condition.bool_threshold === true;
125	    const actual = readBoolMetric(metrics, platform, metric);
126	    if (actual !== required) {
127	      return { metric, platform, required, actual };
128	    }
129	    return null;
130	  }
131	  // Other operators (eq/contains/lte/etc.) are reserved for post-conditions
132	  // (e.g. post_must_mention uses 'contains') — never reachable here because
133	  // this function is only called for kind='pre'. If a future migration adds
134	  // a pre-condition with an unknown operator, skip it rather than fail it.
135	  return null;
136	}
137	
138	function readNumericMetric(
139	  metrics: CreatorProfileRow,
140	  platform: Platform | null,
141	  metric: string,
142	): number | null {
143	  if (platform === "tiktok") {
144	    switch (metric) {
145	      case "min_followers":
146	        return metrics.tiktok_follower_count;
147	      case "min_avg_views_last_n":
148	        return metrics.tiktok_avg_views_last_10;
149	      case "min_total_likes":
150	        return metrics.tiktok_total_likes;
151	      case "min_videos_posted":
152	        return metrics.tiktok_video_count;
153	      default:
154	        return null;
155	    }
156	  }
157	  if (platform === "instagram") {
158	    switch (metric) {
159	      case "min_followers":
160	        return metrics.instagram_follower_count;
161	      case "min_avg_views_last_n":
162	        return metrics.instagram_avg_views_last_10;
163	      case "min_videos_posted":
164	        return metrics.instagram_media_count;
165	      default:
166	        return null;
167	    }
168	  }
169	  return null;
170	}
171	
172	function readBoolMetric(
173	  metrics: CreatorProfileRow,
174	  platform: Platform | null,
175	  metric: string,
176	): boolean | null {
177	  if (platform === "tiktok" && metric === "verified_only") {
178	    return metrics.tiktok_is_verified;
179	  }
180	  return null;
181	}
182	
183	Deno.serve(async (req) => {
184	  if (req.method === "OPTIONS") {
185	    return new Response(null, { status: 204, headers: corsHeaders });
186	  }
187	  if (req.method !== "POST") {
188	    return jsonResponse(405, { error: "METHOD_NOT_ALLOWED" });
189	  }
190	
191	  const token = bearerToken(req);
192	  if (!token) return jsonResponse(401, { error: "UNAUTHORIZED" });
193	
194	  let claims;
195	  try {
196	    claims = await verifyJwt(token);
197	  } catch {
198	    return jsonResponse(401, { error: "UNAUTHORIZED" });
199	  }
200	  if (claims.role !== "creator") {
201	    return jsonResponse(403, { error: "FORBIDDEN" });
202	  }
203	
204	  let body: DetailRequest;
205	  try {
206	    body = await req.json();
207	  } catch {
208	    return jsonResponse(400, { error: "INVALID_JSON" });
209	  }
210	
211	  const listingId =
212	    typeof body.listing_id === "string" && UUID_RE.test(body.listing_id)
213	      ? body.listing_id
214	      : null;
215	  if (!listingId) {
216	    return jsonResponse(400, { error: "INVALID_REQUEST" });
217	  }
218	
219	  const supabaseUrl = Deno.env.get("SUPABASE_URL");
220	  const serviceRoleKey = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY");
221	  if (!supabaseUrl || !serviceRoleKey) {
222	    return jsonResponse(500, { error: "SERVER_MISCONFIGURED" });
223	  }
224	
225	  const supabase = createClient(supabaseUrl, serviceRoleKey, {
226	    auth: { persistSession: false, autoRefreshToken: false },
227	  });
228	
229	  const { data: listing, error: listingError } = await supabase
230	    .from("listings")
231	    .select("*")
232	    .eq("id", listingId)
233	    .maybeSingle();
234	
235	  if (listingError) {
236	    console.error("listings lookup failed", listingError);
237	    return jsonResponse(500, { error: "DB_ERROR" });
238	  }
239	  // Drafts are never visible to non-owners; any creator request for a
240	  // draft listing collapses to 404 so id existence doesn't leak across
241	  // listers.
242	  if (!listing || listing.status === "draft") {
243	    return jsonResponse(404, { error: "LISTING_NOT_FOUND" });
244	  }
245	
246	  const versionId = listing.current_version_id as string | null;
247	  if (!versionId) {
248	    // Data-integrity guard — every non-draft listing should have a current
249	    // version by trigger (us_010). If one is missing, surface DB_ERROR
250	    // rather than returning an inconsistent response to the client.
251	    console.error("listing missing current_version_id", listing.id);
252	    return jsonResponse(500, { error: "DB_ERROR" });
253	  }
254	
255	  const [conditionsRes, videosRes, profileRes, appsRes] = await Promise.all([
256	    supabase
257	      .from("listing_conditions")
258	      .select("*")
259	      .eq("listing_version_id", versionId)
260	      .order("kind", { ascending: true })
261	      .order("metric", { ascending: true }),
262	    supabase
263	      .from("sample_videos")
264	      .select("*")
265	      .eq("listing_version_id", versionId)
266	      .order("sort_order", { ascending: true }),
267	    supabase
268	      .from("creator_profiles")
269	      .select(
270	        "tiktok_follower_count,tiktok_avg_views_last_10,tiktok_total_likes," +
271	          "tiktok_video_count,tiktok_is_verified,instagram_follower_count," +
272	          "instagram_avg_views_last_10,instagram_media_count",
273	      )
274	      .eq("user_id", claims.sub)
275	      .maybeSingle(),
276	    supabase
277	      .from("applications")
278	      .select("id")
279	      .eq("listing_id", listingId)
280	      .eq("creator_id", claims.sub)
281	      .in("status", ["pending", "approved"])
282	      .limit(1),
283	  ]);
284	
285	  if (conditionsRes.error) {
286	    console.error("listing_conditions lookup failed", conditionsRes.error);
287	    return jsonResponse(500, { error: "DB_ERROR" });
288	  }
289	  if (videosRes.error) {
290	    console.error("sample_videos lookup failed", videosRes.error);
291	    return jsonResponse(500, { error: "DB_ERROR" });
292	  }
293	  if (profileRes.error) {
294	    console.error("creator_profiles lookup failed", profileRes.error);
295	    return jsonResponse(500, { error: "DB_ERROR" });
296	  }
297	  if (appsRes.error) {
298	    console.error("applications lookup failed", appsRes.error);
299	    return jsonResponse(500, { error: "DB_ERROR" });
300	  }
301	
302	  const conditions = (conditionsRes.data ?? []) as ConditionRow[];
303	  const preConditions = conditions.filter((c) => c.kind === "pre");
304	  const postConditions = conditions.filter((c) => c.kind === "post");
305	
306	  // Creator profile is created by the signup flow (US-014) so every
307	  // creator JWT should have one, but treat a missing row as fully-null
308	  // metrics — fail-closed on every numeric threshold.
309	  const metrics: CreatorProfileRow = profileRes.data ?? {
310	    tiktok_follower_count: null,
311	    tiktok_avg_views_last_10: null,
312	    tiktok_total_likes: null,
313	    tiktok_video_count: null,
314	    tiktok_is_verified: null,
315	    instagram_follower_count: null,
316	    instagram_avg_views_last_10: null,
317	    instagram_media_count: null,
318	  };
319	
320	  const failed: FailedCondition[] = [];
321	  for (const c of preConditions) {
322	    const miss = evaluatePreCondition(c, metrics);
323	    if (miss) failed.push(miss);
324	  }
325	  const eligible = failed.length === 0;
326	  const hasActiveApplication = (appsRes.data ?? []).length > 0;
327	
328	  return jsonResponse(200, {
329	    listing,
330	    pre_conditions: preConditions,
331	    post_conditions: postConditions,
332	    sample_videos: videosRes.data ?? [],
333	    eligibility: {
334	      eligible,
335	      failed_conditions: failed,
336	      has_active_application: hasActiveApplication,
337	    },
338	  });
339	});
