1	// Smoke test for the deployed get-listing-detail edge function (US-039).
2	//
3	// Usage: bun run scripts/test/get-listing-detail.ts
4	// Requires SUPABASE_URL and SUPABASE_ANON_KEY always. MARKETIFY_JWT_SECRET
5	// unlocks JWT-authed tests; SUPABASE_SERVICE_ROLE_KEY unlocks the
6	// ineligibility case (needs to mutate creator_profiles.tiktok_follower_count
7	// below threshold + restore it). Missing either secret SKIPs the
8	// corresponding assertions with a printed notice rather than failing.
9	//
10	// Asserts:
11	//   1. Missing Authorization → 401 UNAUTHORIZED                               [always]
12	//   2. Non-Bearer token → 401 UNAUTHORIZED                                    [always]
13	//   3. JWT signed with wrong secret → 401 UNAUTHORIZED                        [always]
14	//   4. Lister-role JWT → 403 FORBIDDEN                                        [jwtSecret]
15	//   5. Malformed JSON body → 400 INVALID_JSON                                 [jwtSecret]
16	//   6. Missing listing_id → 400 INVALID_REQUEST                               [jwtSecret]
17	//   7. Non-UUID listing_id → 400 INVALID_REQUEST                              [jwtSecret]
18	//   8. Unknown listing_id → 404 LISTING_NOT_FOUND                             [jwtSecret]
19	//   9. Seed creator + seed listing (1k/500 thresholds, creator has 93.7M/15k)
20	//      → 200 with eligible:true, pre/post conditions split, sample_videos,
21	//        has_active_application:false                                         [jwtSecret]
22	//  10. Same call after mutating creator_profiles.tiktok_follower_count to 500
23	//      → 200 with eligible:false AND failed_conditions including tiktok
24	//        min_followers with required=1000, actual=500                         [jwtSecret + serviceRole]
25	
26	const supabaseUrl = process.env.SUPABASE_URL;
27	const anonKey = process.env.SUPABASE_ANON_KEY;
28	const serviceRoleKey = process.env.SUPABASE_SERVICE_ROLE_KEY;
29	const jwtSecret = process.env.MARKETIFY_JWT_SECRET;
30	if (!supabaseUrl || !anonKey) {
31	  console.error("SUPABASE_URL and SUPABASE_ANON_KEY are required in .env");
32	  process.exit(1);
33	}
34	if (!jwtSecret) {
35	  console.log(
36	    "MARKETIFY_JWT_SECRET missing — skipping assertions 4–10",
37	  );
38	}
39	if (!serviceRoleKey) {
40	  console.log(
41	    "SUPABASE_SERVICE_ROLE_KEY missing — skipping assertion 10 (ineligible)",
42	  );
43	}
44	
45	const endpoint = `${supabaseUrl}/functions/v1/get-listing-detail`;
46	
47	// Seed fixtures — same UUIDs used by other smoke tests.
48	const SEED_CREATOR_USER_ID = "11111111-1111-1111-1111-111111111002";
49	const SEED_LISTING_ID = "11111111-1111-1111-1111-111111111010";
50	
51	const encoder = new TextEncoder();
52	
53	function b64url(bytes: Uint8Array): string {
54	  let s = "";
55	  for (const b of bytes) s += String.fromCharCode(b);
56	  return btoa(s).replaceAll("+", "-").replaceAll("/", "_").replace(/=+$/, "");
57	}
58	
59	async function signMarketifyJwt(
60	  claims: { sub: string; role: "creator" | "lister"; session_id: string },
61	  secret: string,
62	): Promise<string> {
63	  const now = Math.floor(Date.now() / 1000);
64	  const payload = { ...claims, iat: now, exp: now + 300 };
65	  const header = b64url(encoder.encode(JSON.stringify({ alg: "HS256", typ: "JWT" })));
66	  const body = b64url(encoder.encode(JSON.stringify(payload)));
67	  const signingInput = `${header}.${body}`;
68	  const key = await crypto.subtle.importKey(
69	    "raw",
70	    encoder.encode(secret),
71	    { name: "HMAC", hash: "SHA-256" },
72	    false,
73	    ["sign"],
74	  );
75	  const sig = await crypto.subtle.sign("HMAC", key, encoder.encode(signingInput));
76	  return `${signingInput}.${b64url(new Uint8Array(sig))}`;
77	}
78	
79	async function post(
80	  bodyValue: string | Record<string, unknown> | null,
81	  authHeader: string | null,
82	) {
83	  const headers: Record<string, string> = {
84	    "Content-Type": "application/json",
85	    apikey: anonKey!,
86	  };
87	  if (authHeader) headers["Authorization"] = authHeader;
88	  const res = await fetch(endpoint, {
89	    method: "POST",
90	    headers,
91	    body: bodyValue == null
92	      ? undefined
93	      : typeof bodyValue === "string"
94	      ? bodyValue
95	      : JSON.stringify(bodyValue),
96	  });
97	  const data = await res.json().catch(() => null);
98	  return { status: res.status, data };
99	}
100	
101	function expect(label: string, cond: boolean, ctx: unknown) {
102	  if (!cond) {
103	    console.error(`FAIL ${label}:`, JSON.stringify(ctx, null, 2));
104	    process.exit(1);
105	  }
106	  console.log(`ok — ${label}`);
107	}
108	
109	async function setCreatorMetric(
110	  column: "tiktok_follower_count",
111	  value: number | null,
112	): Promise<void> {
113	  const res = await fetch(
114	    `${supabaseUrl}/rest/v1/creator_profiles?user_id=eq.${SEED_CREATOR_USER_ID}`,
115	    {
116	      method: "PATCH",
117	      headers: {
118	        apikey: serviceRoleKey!,
119	        Authorization: `Bearer ${serviceRoleKey}`,
120	        "Content-Type": "application/json",
121	        Prefer: "return=minimal",
122	      },
123	      body: JSON.stringify({ [column]: value }),
124	    },
125	  );
126	  if (!res.ok) {
127	    throw new Error(`setCreatorMetric failed: ${res.status} ${await res.text()}`);
128	  }
129	}
130	
131	// Snapshot the seed creator's tiktok_follower_count so we can restore it
132	// after the ineligibility case. Only fetched when we have service role.
133	let originalTiktokFollowerCount: number | null = null;
134	if (serviceRoleKey) {
135	  const snapRes = await fetch(
136	    `${supabaseUrl}/rest/v1/creator_profiles?user_id=eq.${SEED_CREATOR_USER_ID}&select=tiktok_follower_count`,
137	    {
138	      headers: {
139	        apikey: serviceRoleKey,
140	        Authorization: `Bearer ${serviceRoleKey}`,
141	      },
142	    },
143	  );
144	  if (!snapRes.ok) {
145	    console.error("creator_profiles snapshot failed:", await snapRes.text());
146	    process.exit(1);
147	  }
148	  const rows = (await snapRes.json()) as Array<{ tiktok_follower_count: number | null }>;
149	  if (rows.length === 0) {
150	    console.error(
151	      "seed creator_profiles missing — run seed fixtures before this test",
152	    );
153	    process.exit(1);
154	  }
155	  originalTiktokFollowerCount = rows[0].tiktok_follower_count;
156	}
157	
158	let restored = false;
159	async function restore() {
160	  if (restored || !serviceRoleKey) return;
161	  restored = true;
162	  await setCreatorMetric("tiktok_follower_count", originalTiktokFollowerCount);
163	}
164	
165	try {
166	  // 1. No Authorization header
167	  {
168	    const r = await post({ listing_id: SEED_LISTING_ID }, null);
169	    expect(
170	      "missing auth → 401 UNAUTHORIZED",
171	      r.status === 401 && r.data?.error === "UNAUTHORIZED",
172	      r,
173	    );
174	  }
175	
176	  // 2. Non-Bearer scheme
177	  {
178	    const r = await post({ listing_id: SEED_LISTING_ID }, "Basic abcdef");
179	    expect(
180	      "non-bearer → 401 UNAUTHORIZED",
181	      r.status === 401 && r.data?.error === "UNAUTHORIZED",
182	      r,
183	    );
184	  }
185	
186	  // 3. JWT signed with wrong secret
187	  {
188	    const badJwt = await signMarketifyJwt(
189	      {
190	        sub: SEED_CREATOR_USER_ID,
191	        role: "creator",
192	        session_id: crypto.randomUUID(),
193	      },
194	      "wrong-secret-" + Math.random().toString(36).slice(2),
195	    );
196	    const r = await post({ listing_id: SEED_LISTING_ID }, `Bearer ${badJwt}`);
197	    expect(
198	      "wrong-secret JWT → 401 UNAUTHORIZED",
199	      r.status === 401 && r.data?.error === "UNAUTHORIZED",
200	      r,
201	    );
202	  }
203	
204	  if (jwtSecret) {
205	    // 4. Lister-role JWT (valid signature, wrong role)
206	    {
207	      const listerJwt = await signMarketifyJwt(
208	        { sub: crypto.randomUUID(), role: "lister", session_id: crypto.randomUUID() },
209	        jwtSecret,
210	      );
211	      const r = await post({ listing_id: SEED_LISTING_ID }, `Bearer ${listerJwt}`);
212	      expect(
213	        "lister-role JWT → 403 FORBIDDEN",
214	        r.status === 403 && r.data?.error === "FORBIDDEN",
215	        r,
216	      );
217	    }
218	
219	    const creatorJwt = await signMarketifyJwt(
220	      {
221	        sub: SEED_CREATOR_USER_ID,
222	        role: "creator",
223	        session_id: crypto.randomUUID(),
224	      },
225	      jwtSecret,
226	    );
227	    const creatorAuth = `Bearer ${creatorJwt}`;
228	
229	    // 5. Malformed JSON body
230	    {
231	      const r = await post("{not-json", creatorAuth);
232	      expect(
233	        "malformed JSON → 400 INVALID_JSON",
234	        r.status === 400 && r.data?.error === "INVALID_JSON",
235	        r,
236	      );
237	    }
238	
239	    // 6. Missing listing_id
240	    {
241	      const r = await post({}, creatorAuth);
242	      expect(
243	        "missing listing_id → 400 INVALID_REQUEST",
244	        r.status === 400 && r.data?.error === "INVALID_REQUEST",
245	        r,
246	      );
247	    }
248	
249	    // 7. Non-UUID listing_id
250	    {
251	      const r = await post({ listing_id: "not-a-uuid" }, creatorAuth);
252	      expect(
253	        "non-UUID listing_id → 400 INVALID_REQUEST",
254	        r.status === 400 && r.data?.error === "INVALID_REQUEST",
255	        r,
256	      );
257	    }
258	
259	    // 8. Unknown listing_id
