328	// Re-reads last_scrape_attempt_at after the CAS UPDATE returned zero rows
329	// so the 429 carries an accurate retry_after_sec. If the read fails for
330	// any reason we fall back to the full throttle window rather than leak a
331	// DB_ERROR on a path that's already a rejection.
332	// deno-lint-ignore no-explicit-any -- see note above on supabase-js generics
333	async function computeRetryAfterSec(
334	  supabase: any,
335	  socialLinkId: string,
336	  nowMs: number,
337	): Promise<number> {
338	  const { data, error } = await supabase
339	    .from("social_links")
340	    .select("last_scrape_attempt_at")
341	    .eq("id", socialLinkId)
342	    .maybeSingle();
343	  if (error || !data?.last_scrape_attempt_at) {
344	    return THROTTLE_SECS;
345	  }
346	  const lastMs = Date.parse(data.last_scrape_attempt_at);
347	  if (!Number.isFinite(lastMs)) return THROTTLE_SECS;
348	  const elapsedSec = Math.floor((nowMs - lastMs) / 1000);
349	  return Math.max(1, THROTTLE_SECS - elapsedSec);
350	}
